#include <bits/stdc++.h>
using namespace std;

string solve(string& s) {
    int n = s.length();
    bool dp[1000][1000] = {false};
    string ans = "";
    int maxLen = -1;

    // Fill dp table
    for(int gap = 0; gap < n; gap++) {
        for(int i = 0, j = gap; j < n; i++, j++) {
            if(gap == 0) {
                // Single character
                dp[i][j] = true;
            }
            else if(gap == 1) {
                // Two characters
                dp[i][j] = (s[i] == s[j]);
            }
            else {
                // More than two characters
                dp[i][j] = (s[i] == s[j] && dp[i+1][j-1]);
            }

            // Update answer if current palindrome is longer
            if(dp[i][j] && maxLen < j - i + 1) {
                ans = s.substr(i, j - i + 1);
                maxLen = j - i + 1;
            }
        }
    }

    return ans;
}

int main() {
    int n;
    cin >> n;
    string s;
    cin >> s;
    cout << solve(s) << endl;
    return 0;
}
